function parseLexicalDeclaration(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  kind: BindingKind,
  origin: Origin,
): ESTree.VariableDeclaration {
  // BindingList ::
