  Block = 1 << 1,
  CatchStatement = 1 << 2,
  SwitchStatement = 1 << 3,
  TryStatement = 1 << 4,
  CatchBlock = 1 << 5,
  FunctionBody = 1 << 6,
  FunctionRoot = 1 << 7,
  FunctionParams = 1 << 8,
  ArrowParams = 1 << 9,
